const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface CropPrice {
  id: string;
  name: string;
  price: string;
  unit: string;
  change: string;
  trend: 'up' | 'down';
  color: string;
}

export interface ChartData {
  day: string;
