}

import { GoogleGenAI } from "@google/genai";

export const getMarketInsight = async () => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Analyze the current agricultural market trends in Myanmar for Pigeon Peas and Black Gram and give a one-sentence advice to a farmer in Myanmar Unicode. Be encouraging and concise.",
      config: {
        systemInstruction: "You are a professional agricultural market analyst specializing in Myanmar crops. Respond ONLY in Myanmar Unicode.",
        temperature: 0.7,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Error fetching AI insight:", error);
    return "ပဲစင်းငုံစျေးနှုန်းသည် မနက်ဖြန်တွင် ၅% ခန့် ထပ်တက်ရန် အလားအလာရှိပါသည်။ ယနေ့ မရောင်းဘဲ ခဏစောင့်ရန် အကြံပြုပါသည်။";
  }
};

