import React, { useEffect, useState } from 'react';
import { Lightbulb, RefreshCw } from 'lucide-react';
import { getMarketInsight } from '../services/geminiService';

const AIInsight: React.FC = () => {
  const [insight, setInsight] = useState<string>("ခေတ္တစောင့်ဆိုင်းပါ...");
  const [loading, setLoading] = useState(false);

  const fetchInsight = async () => {
    setLoading(true);
    const text = await getMarketInsight();
    if (text) setInsight(text);
    setLoading(false);
  };

  useEffect(() => {
    fetchInsight();
  }, []);

  return (
    <div className="mx-4 mt-6">
      <div className="bg-emerald-50 border border-emerald-100 p-5 rounded-3xl relative overflow-hidden group">
        <div className="flex items-start gap-3">
          <div className="bg-emerald-200/50 p-2 rounded-xl">
            <Lightbulb className="text-emerald-700" size={24} />
          </div>
          <div className="flex-1">
            <div className="flex justify-between items-center mb-1">
              <h3 className="font-bold text-emerald-900 text-sm opacity-80 uppercase tracking-wider">AI အကြံပြုချက်</h3>
              <button 
                onClick={fetchInsight}
                className={`text-emerald-600 hover:text-emerald-800 transition-all ${loading ? 'animate-spin' : ''}`}
              >
                <RefreshCw size={14} />
              </button>
            </div>
            <p className="text-emerald-900 leading-relaxed font-medium">
              {insight}
            </p>
          </div>
        </div>
        <div className="absolute top-0 right-0 -mt-4 -mr-4 w-16 h-16 bg-emerald-200/20 rounded-full blur-2xl group-hover:bg-emerald-200/40 transition-all"></div>
      </div>
    </div>
  );
};

export default AIInsight;

