interface CropSelectionProps {
  onConfirm: (selectedIds: string[]) => void;
  onBack: () => void;
}

const CropSelection: React.FC<CropSelectionProps> = ({ onConfirm, onBack }) => {
  const [selectedIds, setSelectedIds] = useState<string[]>(['1', '2']);
  const [selectedRegion, setSelectedRegion] = useState('shan');
  const [searchQuery, setSearchQuery] = useState('');

  const toggleCrop = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const filteredCrops = ALL_CROPS.filter(crop => 
    crop.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const getCategoryIcon = (iconName: string) => {
    switch (iconName) {
      case 'Bean': return <Bean size={20} />;
      case 'Droplet': return <Droplet size={20} />;
