import React from 'react';
import { TrendingUp, TrendingDown, Minus } from 'lucide-react';
import { CropPrice } from '../types';

interface CropCardProps {
  crop: CropPrice;
  onClick?: () => void;
}

const CropCard: React.FC<CropCardProps> = ({ crop, onClick }) => {
  const isUp = crop.trend === 'up' && crop.change !== '၀';
  const isStable = crop.change === '၀';

  return (
    <div 
      onClick={onClick}
      className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 hover:shadow-md transition-all cursor-pointer flex flex-col justify-between active:scale-[0.97] min-h-[140px]"
    >
      <div className="flex items-start justify-between">
        <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-bold text-sm ${
          isUp ? 'bg-emerald-50 text-emerald-600' : isStable ? 'bg-slate-50 text-slate-600' : 'bg-red-50 text-red-600'
        }`}>
          {crop.name.charAt(0)}
        </div>
        <div className={`flex items-center gap-1 text-[10px] font-black px-2 py-1 rounded-full ${
          isUp ? 'bg-emerald-100 text-emerald-700' : isStable ? 'bg-slate-100 text-slate-500' : 'bg-red-100 text-red-700'
        }`}>
          {isUp ? <TrendingUp size={10} /> : isStable ? <Minus size={10} /> : <TrendingDown size={10} />}
          <span>{isStable ? 'ဈေးငြိမ်' : crop.change}</span>
        </div>
      </div>

      <div className="mt-4">
        <h3 className="font-bold text-slate-800 text-sm mb-1 leading-tight">{crop.name}</h3>
        <p className="text-xl font-black text-slate-900 tracking-tight">
          {crop.price}
          <span className="text-xs font-medium text-slate-400 ml-1">ကျပ်</span>
        </p>
        <p className="text-[10px] text-slate-400 mt-1 font-medium">{crop.unit}</p>
      </div>
    </div>
  );
};

