import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export interface MarketAnalysis {
  advice: string;
  reasoning: string;
  confidence: number;
  sources: { title: string; uri: string }[];
}

export const getMarketInsight = async (): Promise<MarketAnalysis | null> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Analyze the latest agricultural market news in Myanmar (today/this week). Focus on pulses like Pigeon Peas and Black Gram, considering Indian export demand and current harvests. Provide: 1. A short advice (Sell or Hold), 2. A concise reasoning sentence, 3. A confidence score (0-100). Respond in Myanmar Unicode.",
      config: {
        systemInstruction: "You are a senior agricultural economist. Analyze market trends using Google Search. Return your response in a clear format: Advice: [text], Reasoning: [text], Confidence: [number]. Use Myanmar Unicode for text.",
        tools: [{ googleSearch: {} }],
        temperature: 0.2,
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    // Simple parsing logic for the structured response
    const adviceMatch = text.match(/Advice:\s*(.*)/i);
    const reasoningMatch = text.match(/Reasoning:\s*(.*)/i);
    const confidenceMatch = text.match(/Confidence:\s*(\d+)/i);

    const sources = groundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || "Market Source",
        uri: chunk.web?.uri || ""
      }));

    return {
      advice: adviceMatch ? adviceMatch[1].trim() : "အခြေအနေ စောင့်ကြည့်ရန်",
      reasoning: reasoningMatch ? reasoningMatch[1].trim() : "စျေးကွက်သတင်းများကို ခွဲခြမ်းစိတ်ဖြာနေပါသည်။",
      confidence: confidenceMatch ? parseInt(confidenceMatch[1]) : 80,
      sources: sources.slice(0, 2)
    };
  } catch (error) {
    console.error("Error fetching AI insight:", error);
    return null;
  }
};

