import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export interface CropUpdate {
  id: string;
  currentPrice: string;
  change: string;
  trend: 'up' | 'down';
  source: string;
}

export interface MarketAnalysis {
  advice: string;
  reasoning: string;
  confidence: number;
  sources: { title: string; uri: string }[];
  cropUpdates: CropUpdate[];
}

export const getMarketInsight = async (): Promise<MarketAnalysis | null> => {
  try {
    const prompt = `
      Analyze Myanmar's agricultural market for February 2026. 
      Using Google Search, find the latest prices for:
      1. Black Gram (မတ်ပဲ FAQ)
      2. Pigeon Pea (ပဲစင်းငုံနီ)
      3. Garlic (ကြက်သွန်ဖြူ - ရှမ်း/တောင်ကြီး)
      4. White Sesame (နှမ်းဖြူ)

      Consider:
      - Indian demand for pulses.
      - Current USD/MMK exchange rate trends.
      - Arrival of new crops (harvest season).

      Respond in Myanmar Unicode with this exact structure:
      Advice: [Short Sell/Hold advice]
      Reasoning: [One sentence explaining why based on India demand or supply]
      Confidence: [Number 0-100]
      Prices:
      - 1: [Price] | [Change] | [Trend up/down] | [Source Name]
      - 2: [Price] | [Change] | [Trend up/down] | [Source Name]
      - 3: [Price] | [Change] | [Trend up/down] | [Source Name]
      - 4: [Price] | [Change] | [Trend up/down] | [Source Name]
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are an expert Myanmar agricultural market analyst. Use Google Search to find real-time data. Always use Myanmar Unicode. If it's harvest season and supply is high, suggest selling. If India demand is spiking and stocks are low, suggest holding.",
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    const adviceMatch = text.match(/Advice:\s*(.*)/i);
    const reasoningMatch = text.match(/Reasoning:\s*(.*)/i);
    const confidenceMatch = text.match(/Confidence:\s*(\d+)/i);

    // Parse individual crop prices
    const cropUpdates: CropUpdate[] = [];
    const priceLines = text.match(/-\s*(\d):\s*(.*)/g) || [];

    priceLines.forEach(line => {
      const parts = line.split('|').map(p => p.trim());
      const idMatch = line.match(/-\s*(\d):/);
      if (idMatch && parts.length >= 4) {
        cropUpdates.push({
          id: idMatch[1],
          currentPrice: parts[0].replace(/-\s*\d:\s*/, ''),
          change: parts[1],
          trend: parts[2].toLowerCase().includes('up') ? 'up' : 'down',
          source: parts[3]
        });
      }
    });

    const sources = groundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || "Market Source",
        uri: chunk.web?.uri || ""
      }));

    return {
      advice: adviceMatch ? adviceMatch[1].trim() : "ဈေးကွက်စောင့်ကြည့်ရန်",
      reasoning: reasoningMatch ? reasoningMatch[1].trim() : "အိန္ဒိယဝယ်လိုအားနှင့် ပြည်တွင်းအဝင်ပေါ်မူတည်၍ ခန့်မှန်းထားပါသည်။",
      confidence: confidenceMatch ? parseInt(confidenceMatch[1]) : 85,
      sources: sources.slice(0, 2),
      cropUpdates
    };
  } catch (error) {
    console.error("Error fetching AI insight:", error);
    return null;
  }
};

