      2. မတ်ပဲ (Black Gram FAQ)
      3. နှမ်းဖြူ (White Sesame)
      4. ကြက်သွန်ဖြူ (Garlic - Shan/Taunggyi)

      အချက်အလက်များကို ခွဲခြမ်းစိတ်ဖြာရာတွင်:
      - အိန္ဒိယနိုင်ငံ၏ ပဲဝယ်လိုအား (Indian pulse demand)
      - လက်ရှိ USD/MMK ငွေလဲလှယ်နှုန်း (Exchange rate)
      - သီးနှံပေါ်ဦးပေါ်ဖျား အခြေအနေ (Harvest season arrival)
      တို့ကို ထည့်သွင်းစဉ်းစားပေးပါ။

      Response Structure (Myanmar Unicode ONLY):
      Advice: [ရောင်းရန် သို့မဟုတ် စောင့်ရန် အကြံပြုချက်]
      Reasoning: [အိန္ဒိယဝယ်လိုအား သို့မဟုတ် အဝင်များနေမှုအပေါ် အခြေခံထားသော အကြောင်းပြချက် တစ်ကြောင်း]
      GlobalConfidence: [တစ်ခုလုံးအပေါ် ယုံကြည်မှုအဆင့် 0-100]
      Prices:
      - ID1: [Price] | [Change] | [Trend up/down] | [Source] | [Confidence Score 0-100]
      - ID2: [Price] | [Change] | [Trend up/down] | [Source] | [Confidence Score 0-100]
      - ID3: [Price] | [Change] | [Trend up/down] | [Source] | [Confidence Score 0-100]
      - ID4: [Price] | [Change] | [Trend up/down] | [Source] | [Confidence Score 0-100]
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Complex reasoning task
      contents: prompt,
      config: {
        systemInstruction: "You are a professional agricultural market analyst in Myanmar. Use Google Search to provide REAL-TIME data for February 2026. Be specific about prices and trends. Always respond in Myanmar Unicode. If supply is high due to harvest, suggest selling at a good price. If India demand is high, suggest holding.",
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    const adviceMatch = text.match(/Advice:\s*(.*)/i);
    const reasoningMatch = text.match(/Reasoning:\s*(.*)/i);
    const globalConfidenceMatch = text.match(/GlobalConfidence:\s*(\d+)/i);

    const cropUpdates: CropUpdate[] = [];
    const priceLines = text.match(/-\s*ID(\d):\s*(.*)/g) || [];

    priceLines.forEach(line => {
      const parts = line.split('|').map(p => p.trim());
      const idMatch = line.match(/-\s*ID(\d):/);
      if (idMatch && parts.length >= 5) {
        cropUpdates.push({
          id: idMatch[1],
          currentPrice: parts[0].replace(/-\s*ID\d:\s*/, ''),
          change: parts[1],
          trend: parts[2].toLowerCase().includes('up') ? 'up' : 'down',
          source: parts[3],
          confidence: parseInt(parts[4]) || 80
        });
      }
    });

    const sources = groundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || "စျေးကွက်သတင်း",
        uri: chunk.web?.uri || ""
      }));

    return {
      advice: adviceMatch ? adviceMatch[1].trim() : "စျေးကွက်အခြေအနေကို စောင့်ကြည့်ရန်",
      reasoning: reasoningMatch ? reasoningMatch[1].trim() : "လက်ရှိစျေးကွက်သတင်းများအပေါ် အခြေခံ၍ ခန့်မှန်းထားပါသည်။",
      globalConfidence: globalConfidenceMatch ? parseInt(globalConfidenceMatch[1]) : 85,
      sources: sources.slice(0, 3),
      cropUpdates
    };
  } catch (error) {
    console.error("Error fetching AI insight:", error);
    return null;
  }
};

