    <div className="min-h-screen pb-40 max-w-md mx-auto bg-slate-50 shadow-2xl relative overflow-x-hidden border-x border-slate-100">
      <Header />

      <main className="animate-in fade-in slide-in-from-bottom-6 duration-700">
