              </div>

              <div className="grid grid-cols-2 gap-4">
                {homeCrops.length > 0 ? (
                  homeCrops.map((crop) => (
                    <CropCard 
                      key={crop.id} 
                      crop={crop} 
                      onClick={() => setSelectedCrop(crop)} 
                    />
