                      onClick={() => setIsSelectionMode(true)}
                      className="bg-emerald-600 text-white px-8 py-3 rounded-2xl text-sm font-black shadow-lg shadow-emerald-100 active:scale-95 transition-all"
                    >
                      သီးနှံရွေးရန်
