// services/geminiService.ts

const API_KEY = "YOUR_GEMINI_API_KEY"; // AIzaSyDnWByu3vdpvzTTFMhAs6TYvw4Nn4cR1kY
const BASE_URL = "https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent";

export const fetchLivePrices = async (cropNames: string[]) => {
  const prompt = `
    You are a Myanmar Agriculture Market Expert. 
    Provide the current market prices for: ${cropNames.join(", ")} in Myanmar Kyats.
    Return ONLY a JSON array in this format:
    [
      {"name": "မတ်ပဲ", "price": "၃,၂၀၀,၀၀၀", "change": "+၅,၀၀၀", "trend": "up", "unit": "တစ်တန်"},
      {"name": "တောင်ကြီးပြောင်း", "price": "၁,၂၀၀", "change": "-၁၀", "trend": "down", "unit": "တစ်ပိဿာ"}
    ]
    Use Myanmar Unicode for names. Ensure data is realistic for February 2026.
  `;

  try {
    const response = await fetch(`${BASE_URL}?key=${API_KEY}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts: [{ text: prompt }] }]
      })
    });

    const data = await response.json();
    const text = data.candidates[0].content.parts[0].text;

    // JSON စာသားသက်သက်ပဲ ထွက်လာအောင် Clean လုပ်ခြင်း
    const cleanJson = text.replace(/```json|```/g, "");
    return JSON.parse(cleanJson);
  } catch (error) {
    console.error("Error fetching prices:", error);
    return null;
  }
};

